class Solution:
    def checkOverlap(self, radius, xCenter, yCenter, x1, y1, x2, y2):
        # Check each of the 4 corners, 4 edge segments projected perpendicularly, and interior
        # Equivalent: closest point on rectangle, computed via clamping but using explicit cases
        def dist_sq_point_to_rect(cx, cy):
            # closest x
            if cx < x1:
                px = x1
            elif cx > x2:
                px = x2
            else:
                px = cx
            # closest y
            if cy < y1:
                py = y1
            elif cy > y2:
                py = y2
            else:
                py = cy
            return (px - cx) ** 2 + (py - cy) ** 2
        return dist_sq_point_to_rect(xCenter, yCenter) <= radius * radius

