class Solution:
    def checkOverlap(self, radius, xCenter, yCenter, x1, y1, x2, y2):
        dx = max(x1, min(xCenter, x2)) - xCenter
        dy = max(y1, min(yCenter, y2)) - yCenter
        return dx * dx + dy * dy <= radius * radius

